// Package fileutil provides utilities for efficient file handling operations
package fileutil

import (
	"bufio"
	"io"
	"os"
	"sync"

	"golang.org/x/text/encoding"
	"golang.org/x/text/encoding/htmlindex"
	"golang.org/x/text/transform"
)

// FileReader is a struct optimized for processing large files
type FileReader struct {
	filePath    string
	fileHandle  *os.File
	bufferSize  int
	encodingStr string
	mu          sync.Mutex
	isOpen      bool
}

// NewFileReader creates a new FileReader instance
func NewFileReader(filePath string, bufferSize int, encodingStr string) (*FileReader, error) {
	if bufferSize <= 0 {
		bufferSize = 4096 // Default buffer size
	}

	if encodingStr == "" {
		encodingStr = "utf-8" // Default encoding
	}

	fileHandle, err := os.Open(filePath)
	if err != nil {
		return nil, err
	}

	return &FileReader{
		filePath:    filePath,
		fileHandle:  fileHandle,
		bufferSize:  bufferSize,
		encodingStr: encodingStr,
		isOpen:      true,
	}, nil
}

// ReadAllLines streams content of the file with proper buffer management
// and returns a channel of lines that can be consumed
func (fr *FileReader) ReadAllLines() (<-chan string, <-chan error) {
	linesChan := make(chan string)
	errChan := make(chan error, 1)

	fr.mu.Lock()
	if !fr.isOpen {
		fr.mu.Unlock()
		errChan <- &FileError{Op: "read", Path: fr.filePath, Err: ErrFileClosed}
		close(linesChan)
		return linesChan, errChan
	}
	fr.mu.Unlock()

	go func() {
		defer close(linesChan)
		defer close(errChan)

		// Reset file pointer to beginning
		_, err := fr.fileHandle.Seek(0, 0)
		if err != nil {
			errChan <- &FileError{Op: "seek", Path: fr.filePath, Err: err}
			return
		}

		// Set up encoding reader
		enc, err := htmlindex.Get(fr.encodingStr)
		if err != nil {
			enc = encoding.Nop
		}

		reader := transform.NewReader(fr.fileHandle, enc.NewDecoder())
		bufferedReader := bufio.NewReaderSize(reader, fr.bufferSize)

		for {
			line, err := bufferedReader.ReadString('\n')

			if err != nil && err != io.EOF {
				// Check for file lock or corrupted data errors
				if os.IsPermission(err) {
					errChan <- &FileError{Op: "read", Path: fr.filePath, Err: ErrFileLocked}
				} else {
					errChan <- &FileError{Op: "read", Path: fr.filePath, Err: err}
				}
				return
			}

			// Send the line even if it's the last one without newline
			if line != "" {
				// Trim trailing newline if present
				if len(line) > 0 && line[len(line)-1] == '\n' {
					line = line[:len(line)-1]
				}
				linesChan <- line
			}

			if err == io.EOF {
				break
			}
		}
	}()

	return linesChan, errChan
}

// CloseHandle releases OS resources and prevents resource leaks
func (fr *FileReader) CloseHandle() error {
	fr.mu.Lock()
	defer fr.mu.Unlock()

	if !fr.isOpen {
		return nil
	}

	fr.isOpen = false
	err := fr.fileHandle.Close()
	if err != nil {
		return &FileError{Op: "close", Path: fr.filePath, Err: err}
	}

	return nil
}

// Custom error types
var (
	ErrFileClosed = &FileError{Err: io.ErrClosedPipe, Message: "attempt to read from closed file"}
	ErrFileLocked = &FileError{Message: "file is locked by another process"}
)

// FileError represents errors specific to file operations
type FileError struct {
	Op      string
	Path    string
	Err     error
	Message string
}

// Error implements the error interface
func (e *FileError) Error() string {
	if e.Message != "" {
		return e.Message
	}
	if e.Err != nil {
		return e.Op + " " + e.Path + ": " + e.Err.Error()
	}
	return e.Op + " " + e.Path + ": unknown error"
}

// Unwrap implements the errors.Unwrap interface
func (e *FileError) Unwrap() error {
	return e.Err
}

