use aes_gcm::{
    aead::{Aead, AeadCore, KeyInit, OsRng},
    Aes256Gcm, Key, Nonce,
};
use std::{
    collections::HashMap,
    sync::{Arc, RwLock},
};
use thiserror::Error;

/// Errors that can occur when using SecureStorage
#[derive(Error, Debug)]
pub enum SecureStorageError {
    #[error("Key not found")]
    KeyNotFound,
    #[error("Encryption error: {0}")]
    EncryptionError(String),
    #[error("Decryption error: {0}")]
    DecryptionError(String),
    #[error("Storage error: {0}")]
    StorageError(String),
}

/// Result type for SecureStorage operations
pub type Result<T> = std::result::Result<T, SecureStorageError>;

/// SecureStorage is a thread-safe storage for encrypted data
pub struct SecureStorage {
    data: Arc<RwLock<HashMap<String, Vec<u8>>>>,
    cipher: Aes256Gcm,
}

impl SecureStorage {
    /// Create a new SecureStorage instance with the given encryption key
    pub fn new(encryption_key: &[u8; 32]) -> Self {
        let key = Key::<Aes256Gcm>::from_slice(encryption_key);
        let cipher = Aes256Gcm::new(key);

        SecureStorage {
            data: Arc::new(RwLock::new(HashMap::new())),
            cipher,
        }
    }

    /// Store data with the given key
    pub fn store_data(&self, key: &str, value: &[u8]) -> Result<()> {
        // Generate a random nonce
        let nonce = Aes256Gcm::generate_nonce(&mut OsRng);

        // Encrypt the value
        let encrypted_data = self
            .cipher
            .encrypt(&nonce, value)
            .map_err(|e| SecureStorageError::EncryptionError(e.to_string()))?;

        // Prepend the nonce to the encrypted data
        let mut data_with_nonce = nonce.to_vec();
        data_with_nonce.extend_from_slice(&encrypted_data);

        // Store the data
        let mut data_map = self
            .data
            .write()
            .map_err(|e| SecureStorageError::StorageError(e.to_string()))?;

        data_map.insert(key.to_string(), data_with_nonce);

        Ok(())
    }

    /// Retrieve data for the given key
    pub fn retrieve_data(&self, key: &str) -> Result<Vec<u8>> {
        // Get the data
        let data_map = self
            .data
            .read()
            .map_err(|e| SecureStorageError::StorageError(e.to_string()))?;

        let data_with_nonce = data_map
            .get(key)
            .ok_or(SecureStorageError::KeyNotFound)?
            .clone();

        // First 12 bytes are the nonce
        if data_with_nonce.len() <= 12 {
            return Err(SecureStorageError::DecryptionError(
                "Data is too short".to_string(),
            ));
        }

        let nonce = Nonce::from_slice(&data_with_nonce[..12]);
        let encrypted_data = &data_with_nonce[12..];

        // Decrypt the data
        let decrypted_data = self
            .cipher
            .decrypt(nonce, encrypted_data)
            .map_err(|e| SecureStorageError::DecryptionError(e.to_string()))?;

        Ok(decrypted_data)
    }

    /// Delete data for the given key
    pub fn delete_data(&self, key: &str) -> Result<()> {
        let mut data_map = self
            .data
            .write()
            .map_err(|e| SecureStorageError::StorageError(e.to_string()))?;

        if data_map.remove(key).is_none() {
            return Err(SecureStorageError::KeyNotFound);
        }

        Ok(())
    }
}

