// uploadFile uploads a file to the storage service
func (fm *FileManager) uploadFile(ctx context.Context, key string, data io.Reader, metadata *FileMetadata) error {
	if key == "" || data == nil {
		return ErrInvalidFile
	}

	if metadata == nil {
		metadata = &FileMetadata{
			Name:      key,
			CreatedAt: time.Now(),
			UpdatedAt: time.Now(),
			Tags:      make(map[string]string),
		}
	}

	metaTags := make(map[string]string)
	for k, v := range metadata.Tags {
		metaTags[k] = v
	}
	metaTags["content-type"] = metadata.ContentType
	metaTags["created-at"] = metadata.CreatedAt.Format(time.RFC3339)
	metaTags["updated-at"] = time.Now().Format(time.RFC3339)

	err := fm.provider.Upload(ctx, key, data, metaTags)
	if err != nil {
		return fmt.Errorf("%w: %v", ErrUploadFailed, err)
	}

	// Update metadata cache
	fm.mu.Lock()
	metadata.UpdatedAt = time.Now()
	fm.cache[key] = *metadata
	fm.mu.Unlock()

	return nil
}

// downloadFile downloads a file from the storage service
func (fm *FileManager) downloadFile(ctx context.Context, key string) (io.ReadCloser, *FileMetadata, error) {
	if key == "" {
		return nil, nil, ErrInvalidFile
	}

	reader, tags, err := fm.provider.Download(ctx, key)
	if err != nil {
		return nil, nil, fmt.Errorf("%w: %v", ErrDownloadFailed, err)
	}

	metadata := &FileMetadata{
		Name:        key,
		ContentType: tags["content-type"],
		Tags:        make(map[string]string),
	}

	// Copy relevant tags to metadata
	for k, v := range tags {
		switch k {
		case "content-type":
			metadata.ContentType = v
		case "created-at":
			t, _ := time.Parse(time.RFC3339, v)
			metadata.CreatedAt = t
		case "updated-at":
			t, _ := time.Parse(time.RFC3339, v)
			metadata.UpdatedAt = t
		default:
			metadata.Tags[k] = v
		}
