        // Size-based anomaly detection
        const zScore = (@as(f64, @floatFromInt(packet.size)) - config.meanPacketSize) / config.stdDevPacketSize;
        if (@abs(zScore) > 3.0) {
            const anomalyMsg = try std.fmt.allocPrint(allocator, "Size anomaly: {d} bytes (z-score: {d:.2})", .{packet.size, zScore});
            try anomalies.append(anomalyMsg);
            SizeAlerts += 1;
            TotalAlerts += 1;
        }

        // Protocol-based anomaly detection
        if (!config.normalProtocols.contains(packet.protocol)) {
            const anomalyMsg = try std.fmt.allocPrint(allocator, "Protocol anomaly: {s}", .{packet.protocol});
            try anomalies.append(anomalyMsg);
            ProtocolAlerts += 1;
            TotalAlerts += 1;
        }

        // Destination-based anomaly detection
        if (!config.expectedDestinations.contains(packet.destination)) {
            const anomalyMsg = try std.fmt.allocPrint(allocator, "Destination anomaly: {s}", .{packet.destination});
            try anomalies.append(anomalyMsg);
            DestinationAlerts += 1;
            TotalAlerts += 1;
        }
    }

    // Calculate rate-based anomalies
    if (packets.len > 0) {
        const startTime = packets[0].timestamp;
        const endTime = packets[packets.len - 1].timestamp;
        const durationSecs = @as(f64, @floatFromInt(endTime - startTime)) / 1000.0;
        if (durationSecs > 0) {
            const packetsPerSecond = @as(f64, @floatFromInt(packets.len)) / durationSecs;
            if (packetsPerSecond > @as(f64, @floatFromInt(config.maxPacketsPerSecond))) {
                const anomalyMsg = try std.fmt.allocPrint(allocator, "Rate anomaly: {d:.2} packets/sec", .{packetsPerSecond});
                try anomalies.append(anomalyMsg);
                AnomalyAlerts += 1;
                TotalAlerts += 1;
            }
        }
    }

    var result = std.ArrayList(u8).init(allocator);
    if (anomalies.items.len > 0) {
        try result.appendSlice("Anomalies detected:\n");
        for (anomalies.items) |anomaly| {
            try result.appendSlice("- ");
            try result.appendSlice(anomaly);
            try result.appendSlice("\n");
        }
    } else {
        try result.appendSlice("No anomalies detected.");
    }

    return result.toOwnedSlice();
}

