pub fn generate_reports(packets: []const PacketInfo, anomalies: []const u8, config: baseline_config) ![]const u8 {
    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    const allocator = gpa.allocator();
    defer _ = gpa.deinit();

    var report = std.ArrayList(u8).init(allocator);

    try report.appendSlice("# Network Traffic Analysis Report\n\n");
    try report.appendSlice("## Summary\n\n");

    const timestamp = std.time.timestamp();
    const timeStr = try std.fmt.allocPrint(allocator, "{d}", .{timestamp});
    try report.appendSlice("- Generated at: ");
    try report.appendSlice(timeStr);
    try report.appendSlice("\n");

    const packetCount = try std.fmt.allocPrint(allocator, "{d}", .{packets.len});
    try report.appendSlice("- Packets analyzed: ");
    try report.appendSlice(packetCount);
    try report.appendSlice("\n");

    const alertCount = try std.fmt.allocPrint(allocator, "{d}", .{TotalAlerts});
    try report.appendSlice("- Total alerts: ");
    try report.appendSlice(alertCount);
    try report.appendSlice("\n\n");

    try report.appendSlice("## Anomaly Detection\n\n");
    try report.appendSlice(anomalies);
    try report.appendSlice("\n\n");

    try report.appendSlice("## Traffic Breakdown\n\n");
    try report.appendSlice("### Protocol Distribution\n\n");

    var protocols = std.StringHashMap(u32).init(allocator);
    defer protocols.deinit();

    for (packets) |packet| {
        const result = try protocols.getOrPut(packet.protocol);
        if (result.found_existing) {
            result.value_ptr.* += 1;
        } else {
            result.value_ptr.* = 1;
        }
    }

    var protocolIter = protocols.iterator();
    try report.appendSlice("| Protocol | Count | Percentage |\n");
    try report.appendSlice("|----------|-------|------------|\n");

    while (protocolIter.next()) |entry| {
        const percentage = @as(f64, @floatFromInt(entry.value_ptr.*)) / @as(f64, @floatFromInt(packets.len)) * 100.0;
        const row = try std.fmt.allocPrint(allocator, "| {s} | {d} | {d:.2}% |\n", .{entry.key_ptr.*, entry.value_ptr.*, percentage});
        try report.appendSlice(row);
    }

    try report.appendSlice("\n### Top Destinations\n\n");

    var destinations = std.StringHashMap(u32).init(allocator);
    defer destinations.deinit();

    for (packets) |packet| {
        const result = try destinations.getOrPut(packet.destination);
        if (result.found_existing) {
            result.value_ptr.* += 1;
        } else {
            result.value_ptr.* = 1;
        }
    }

    var destIter = destinations.iterator();
    try report.appendSlice("| Destination | Count | Percentage |\n");
    try report.appendSlice("|-------------|-------|------------|\n");

    while (destIter.next()) |entry| {
        const percentage = @as(f64, @floatFromInt(entry.value_ptr.*)) / @as(f64, @floatFromInt(packets.len)) * 100.0;
        const row = try std.fmt.allocPrint(allocator, "| {s} | {d} | {d:.2}% |\n", .{entry.key_ptr.*, entry.value_ptr.*, percentage});
        try report.appendSlice(row);
    }

    return report.toOwnedSlice();
}

