pub fn export_metrics(packets: []const PacketInfo) ![]const u8 {
    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
    const allocator = gpa.allocator();
    defer _ = gpa.deinit();

    var metrics = std.ArrayList(u8).init(allocator);

