        totalSize += packet.size;
    }

    const avgSize = if (packets.len > 0) @as(f64, @floatFromInt(totalSize)) / @as(f64, @floatFromInt(packets.len)) else 0;

    // Packet count metric
    const packetCount = try std.fmt.allocPrint(allocator, 
        "# TYPE network_monitor_packet_count counter\n" ++
        "network_monitor_packet_count {d}\n", .{packets.len});
    try metrics.appendSlice(packetCount);

    // Average packet size metric
    const avgPacketSize = try std.fmt.allocPrint(allocator, 
        "# TYPE network_monitor_average_packet_size gauge\n" ++
        "network_monitor_average_packet_size {d:.2}\n", .{avgSize});
    try metrics.appendSlice(avgPacketSize);

    // Total bytes processed metric
    const bytesProcessed = try std.fmt.allocPrint(allocator, 
        "# TYPE network_monitor_bytes_processed counter\n" ++
        "network_monitor_bytes_processed {d}\n", .{totalSize});
    try metrics.appendSlice(bytesProcessed);

    // Alert metrics
    const totalAlerts = try std.fmt.allocPrint(allocator, 
        "# TYPE network_monitor_alerts counter\n" ++
        "network_monitor_alerts{{type=\"total\"}} {d}\n" ++
        "network_monitor_alerts{{type=\"anomaly\"}} {d}\n" ++
        "network_monitor_alerts{{type=\"size\"}} {d}\n" ++
        "network_monitor_alerts{{type=\"protocol\"}} {d}\n" ++
        "network_monitor_alerts{{type=\"destination\"}} {d}\n", 
